evaluators.evaluation_logic:
const checkpoints = [];

const appointmentRequests = JSON.parse(localStorage.getItem('appointment_requests') || '[]');
const appointmentSlots = JSON.parse(localStorage.getItem('appointment_slots') || '[]');
const clinics = JSON.parse(localStorage.getItem('clinic_locations') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');

// Speech Therapy service
const speechService = services.find(s => s && s.code === 'speech_therapy');
const speechServiceId = speechService ? speechService.id : null;

// Main Clinic - Downtown
const mainClinic = clinics.find(l => {
  const name = (l && l.name ? l.name.toLowerCase() : '');
  return name.includes('main') && name.includes('downtown');
});
const mainClinicId = mainClinic ? mainClinic.id : null;

function slotQualifies(slot) {
  if (!slot || !slot.is_available) return false;
  if (speechServiceId && slot.service_id !== speechServiceId) return false;
  if (mainClinicId && slot.location_id !== mainClinicId) return false;
  if (slot.appointment_kind !== 'initial_evaluation') return false;
  if (!slot.start_datetime) return false;
  const t = new Date(slot.start_datetime);
  const y = t.getUTCFullYear();
  const m = t.getUTCMonth() + 1;
  const d = t.getUTCDate();
  const dateStr = String(y).padStart(4, '0') + '-' + String(m).padStart(2, '0') + '-' + String(d).padStart(2, '0');
  if (dateStr < '2026-05-10' || dateStr > '2026-05-20') return false;
  let isWeekday = false;
  if (typeof slot.is_weekday === 'boolean') {
    isWeekday = slot.is_weekday;
  } else {
    const dow = t.getUTCDay();
    isWeekday = dow >= 1 && dow <= 5;
  }
  if (!isWeekday) return false;
  const minutes = t.getUTCHours() * 60 + t.getUTCMinutes();
  if (minutes < 15 * 60) return false; // after or at 3:00 PM
  return true;
}

const qualifyingSlots = appointmentSlots
  .filter(slotQualifies)
  .sort((a, b) => new Date(a.start_datetime) - new Date(b.start_datetime));
const earliestSlot = qualifyingSlots.length ? qualifyingSlots[0] : null;

// Basic candidate: correct type, service, age, location, has slot
const candidateRequestsBasic = appointmentRequests.filter(r => {
  if (!r) return false;
  if (r.request_type !== 'evaluation_specific_slot') return false;
  if (speechServiceId && r.service_id !== speechServiceId) return false;
  if (typeof r.child_age_years !== 'number' || r.child_age_years !== 5) return false;
  if (mainClinicId && r.location_id !== mainClinicId) return false;
  if (!r.appointment_slot_id) return false;
  return true;
});

// CP1 (0.30): At least one request with correct service, age, location, request type, and a specific slot
checkpoints.push({ passed: candidateRequestsBasic.length > 0, weight: 0.3 });

// Filter to those whose slot meets the date/time/weekday/eval constraints
const candidateRequestsWithSlot = candidateRequestsBasic.filter(r => {
  const slot = appointmentSlots.find(s => s.id === r.appointment_slot_id);
  return slotQualifies(slot);
});

// CP2 (0.30): At least one such request whose slot satisfies all scheduling constraints
checkpoints.push({ passed: candidateRequestsWithSlot.length > 0, weight: 0.3 });

// CP3 (0.40): That request uses the earliest qualifying slot in the window
let usedEarliest = false;
if (earliestSlot) {
  usedEarliest = candidateRequestsWithSlot.some(r => r.appointment_slot_id === earliestSlot.id);
}
checkpoints.push({ passed: !!earliestSlot && usedEarliest, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchContext = JSON.parse(localStorage.getItem('task2_searchContext') || 'null');
let comparedIds;
try {
  comparedIds = JSON.parse(localStorage.getItem('task2_comparedTherapistIds') || '[]') || [];
} catch (e) {
  comparedIds = [];
}
if (!Array.isArray(comparedIds)) comparedIds = [];

const therapists = JSON.parse(localStorage.getItem('therapists') || '[]');
const favorites = JSON.parse(localStorage.getItem('favorite_therapists') || '[]');
const appointmentRequests = JSON.parse(localStorage.getItem('appointment_requests') || '[]');

// Qualifying therapists: Autism specialty and serves teens 13–17, sorted by experience desc
const qualifyingTherapists = therapists
  .filter(t => {
    if (!t) return false;
    const hasAutism = Array.isArray(t.specialties) && t.specialties.some(sp => String(sp).toLowerCase() === 'autism');
    const servesTeens = Array.isArray(t.age_groups_served) && t.age_groups_served.includes('teens_13_17');
    return hasAutism && servesTeens;
  })
  .sort((a, b) => (b.years_of_experience || 0) - (a.years_of_experience || 0));

const top1 = qualifyingTherapists[0] || null;
const top2 = qualifyingTherapists[1] || null;

// CP1 (0.25): Search used specialty Autism, ageGroup teens_13_17, sorted by experience_desc
const searchPassed = !!searchContext &&
  String(searchContext.specialty || '').toLowerCase() === 'autism' &&
  searchContext.ageGroup === 'teens_13_17' &&
  (searchContext.sortBy === 'experience_desc' || !searchContext.sortBy);
checkpoints.push({ passed: searchPassed, weight: 0.25 });

// CP2 (0.25): User compared/viewed the first two therapists in that qualifying, experience-sorted list
let comparedTopTwo = false;
if (top1 && top2) {
  comparedTopTwo = comparedIds.includes(top1.id) && comparedIds.includes(top2.id);
}
checkpoints.push({ passed: comparedTopTwo, weight: 0.25 });

// CP3 (0.25): The most-experienced qualifying therapist (top1) was added to favorites
let topFavorited = false;
if (top1) {
  topFavorited = favorites.some(f => f && f.therapist_id === top1.id);
}
checkpoints.push({ passed: topFavorited, weight: 0.25 });

// CP4 (0.25): Appointment request for top1 with teen age, child name, and preferred day/time
let apptOk = false;
if (top1) {
  apptOk = appointmentRequests.some(r => {
    if (!r) return false;
    if (r.request_type !== 'therapist_preference') return false;
    if (r.therapist_id !== top1.id) return false;
    if (typeof r.child_age_years !== 'number' || r.child_age_years < 13 || r.child_age_years > 17) return false;
    if (!r.child_name || !String(r.child_name).trim()) return false;
    if (!r.preferred_day_of_week) return false;
    if (!r.preferred_time_range) return false;
    return true;
  });
}
checkpoints.push({ passed: apptOk, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const savedResources = JSON.parse(localStorage.getItem('saved_resources') || '[]');
const resources = JSON.parse(localStorage.getItem('resource_items') || '[]');
let readingListOpened = false;
try {
  readingListOpened = !!JSON.parse(localStorage.getItem('task3_readingListOpened') || 'false');
} catch (e) {
  readingListOpened = false;
}

// Qualifying resources: sensory processing articles for ages 3–5, reading_time >= 5
const qualifyingResourceIds = resources
  .filter(r => {
    if (!r) return false;
    const isArticle = r.content_type === 'article';
    const topic = (r.primary_topic || '').toLowerCase();
    const hasSensory = topic.includes('sensory processing');
    const hasAge = Array.isArray(r.age_groups) && r.age_groups.includes('ages_3_5');
    const longEnough = typeof r.reading_time_minutes === 'number' && r.reading_time_minutes >= 5;
    return isArticle && hasSensory && hasAge && longEnough;
  })
  .map(r => r.id);

const qualifyingSavedIds = savedResources
  .map(s => s && s.resource_id)
  .filter(id => qualifyingResourceIds.includes(id));
const distinctQualifyingSavedCount = Array.from(new Set(qualifyingSavedIds)).length;

// CP1 (0.60): Saved at least three qualifying sensory processing articles for ages 3–5
checkpoints.push({ passed: distinctQualifyingSavedCount >= 3, weight: 0.6 });

// CP2 (0.40): Reading list was opened and there is at least one qualifying saved article
checkpoints.push({ passed: readingListOpened && distinctQualifyingSavedCount >= 1, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const registrations = JSON.parse(localStorage.getItem('group_registrations') || '[]');
const groupPrograms = JSON.parse(localStorage.getItem('group_programs') || '[]');
const sessionOptions = JSON.parse(localStorage.getItem('group_session_options') || '[]');

// Next calendar month range (mirror of getGroupFilterOptions logic)
const now = new Date();
const year = now.getFullYear();
const month = now.getMonth();
const firstOfNextMonth = new Date(year, month + 1, 1);
const lastOfNextMonth = new Date(year, month + 2, 0);
const startNext = firstOfNextMonth.toISOString();
const endNext = lastOfNextMonth.toISOString();

function isInNextMonth(startDateStr) {
  if (!startDateStr) return false;
  const tIso = new Date(startDateStr).toISOString();
  return tIso >= startNext && tIso <= endNext;
}

const qualifyingGroups = groupPrograms
  .filter(g => {
    if (!g || !g.is_active) return false;
    if (g.group_type !== 'social_skills') return false;
    if (!Array.isArray(g.age_groups) || !g.age_groups.includes('ages_8_10')) return false;
    if (typeof g.price_per_child !== 'number' || g.price_per_child > 50) return false;
    if (!isInNextMonth(g.start_date)) return false;
    return true;
  })
  .sort((a, b) => new Date(a.start_date) - new Date(b.start_date));

const earliestGroup = qualifyingGroups[0] || null;

// Registrations that correspond to qualifying groups with child age 8–10
const regsForQualifyingGroups = registrations.filter(r => {
  const g = groupPrograms.find(gr => gr.id === r.group_program_id);
  if (!g) return false;
  if (!qualifyingGroups.some(q => q.id === g.id)) return false;
  if (typeof r.child_age_years !== 'number' || r.child_age_years < 8 || r.child_age_years > 10) return false;
  return true;
});

// CP1 (0.40): Registered a child aged 8–10 for at least one qualifying social skills group next month under $50
checkpoints.push({ passed: regsForQualifyingGroups.length > 0, weight: 0.4 });

// CP2 (0.30): Registration is for the earliest-starting qualifying group
let registeredForEarliest = false;
if (earliestGroup) {
  registeredForEarliest = regsForQualifyingGroups.some(r => r.group_program_id === earliestGroup.id);
}
checkpoints.push({ passed: !!earliestGroup && registeredForEarliest, weight: 0.3 });

// CP3 (0.30): For that earliest group, a valid session option was chosen and a child name provided
let sessionValid = false;
if (earliestGroup) {
  sessionValid = regsForQualifyingGroups.some(r => {
    if (r.group_program_id !== earliestGroup.id) return false;
    if (!r.child_name || !String(r.child_name).trim()) return false;
    const opt = sessionOptions.find(o => o.id === r.group_session_option_id);
    if (!opt) return false;
    if (opt.group_program_id !== earliestGroup.id) return false;
    return true;
  });
}
checkpoints.push({ passed: !!earliestGroup && sessionValid, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const costEstimates = JSON.parse(localStorage.getItem('cost_estimates') || '[]');
const costItems = JSON.parse(localStorage.getItem('cost_estimate_items') || '[]');
const insurancePlans = JSON.parse(localStorage.getItem('insurance_plans') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');
const contactRequests = JSON.parse(localStorage.getItem('cost_estimate_contact_requests') || '[]');

// Target plan: in-network, notes mention copay after deductible
const targetPlan = insurancePlans.find(p => {
  if (!p || p.network_status !== 'in_network') return false;
  const notes = (p.notes || '').toLowerCase();
  return notes.includes('most families pay only a copay after deductible is met');
}) || null;

const speechService = services.find(s => s && s.code === 'speech_therapy') || null;
const otService = services.find(s => s && s.code === 'occupational_therapy') || null;

let matchingEstimateIds = [];

if (targetPlan && speechService && otService) {
  costEstimates.forEach(ce => {
    if (!ce || ce.insurance_plan_id !== targetPlan.id) return;
    const itemsForCe = costItems.filter(it => it.cost_estimate_id === ce.id);
    const speechItem = itemsForCe.find(it => it.service_id === speechService.id);
    const otItem = itemsForCe.find(it => it.service_id === otService.id);
    if (!speechItem || !otItem) return;
    if (speechItem.sessions_per_month !== 4) return;
    if (otItem.sessions_per_month !== 2) return;
    matchingEstimateIds.push(ce.id);
  });
}

// CP1 (0.50): Calculated an estimate under the correct plan with 4 speech and 2 OT sessions
checkpoints.push({ passed: matchingEstimateIds.length > 0, weight: 0.5 });

// CP2 (0.50): Submitted a contact request for one of these estimates, mentioning the plan name and 4/2 speech/OT mix
let contactOk = false;
if (targetPlan && matchingEstimateIds.length > 0) {
  const planNameLower = targetPlan.name.toLowerCase();
  contactOk = contactRequests.some(req => {
    if (!req || !matchingEstimateIds.includes(req.cost_estimate_id)) return false;
    const msg = (req.message || '').toLowerCase();
    if (!msg.includes(planNameLower)) return false;
    const has4 = msg.includes('4');
    const has2 = msg.includes('2');
    const hasSpeech = msg.includes('speech');
    const hasOt = msg.includes('occupational') || msg.includes('ot');
    return has4 && has2 && hasSpeech && hasOt;
  });
}
checkpoints.push({ passed: contactOk, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const callbacks = JSON.parse(localStorage.getItem('callback_requests') || '[]');
const locations = JSON.parse(localStorage.getItem('clinic_locations') || '[]');

function computeDistance(zipCode, loc) {
  if (!loc) return 20;
  if (zipCode && loc.postal_code === zipCode) return 2;
  if (zipCode && loc.city) return 8;
  return 20;
}

const zip = '94110';
const maxDistance = 15;

const qualifyingLocations = locations
  .map(l => ({ loc: l, distance: computeDistance(zip, l) }))
  .filter(w => w.distance <= maxDistance)
  .filter(w => {
    const l = w.loc;
    const hasFreeParking = !!l.has_free_parking || (Array.isArray(l.amenities) && l.amenities.includes('free_parking'));
    return hasFreeParking && !!l.open_saturday;
  });

const qualifyingLocationIds = qualifyingLocations.map(w => w.loc.id);

// CP1 (0.50): At least one callback requested from a clinic within 15 miles that has free parking and Saturday hours
const callbackForQualifyingLoc = callbacks.find(cb => qualifyingLocationIds.includes(cb.location_id)) || null;
checkpoints.push({ passed: !!callbackForQualifyingLoc, weight: 0.5 });

// Nearest qualifying location
let nearestQualifyingId = null;
if (qualifyingLocations.length > 0) {
  qualifyingLocations.sort((a, b) => a.distance - b.distance);
  nearestQualifyingId = qualifyingLocations[0].loc.id;
}

// CP2 (0.25): Callback was requested specifically for the nearest qualifying clinic
const usedNearest = !!nearestQualifyingId && callbacks.some(cb => cb.location_id === nearestQualifyingId);
checkpoints.push({ passed: usedNearest, weight: 0.25 });

// CP3 (0.25): That callback includes a valid preferred call time, phone number, and a message mentioning Saturday
let callbackDetailsOk = false;
if (nearestQualifyingId) {
  const allowedTimes = ['morning_9_12', 'afternoon_12_4', 'evening_4_7', 'anytime'];
  callbackDetailsOk = callbacks.some(cb => {
    if (cb.location_id !== nearestQualifyingId) return false;
    if (!cb.phone_number || !String(cb.phone_number).trim()) return false;
    if (!allowedTimes.includes(cb.preferred_call_time)) return false;
    const msg = (cb.message || '').toLowerCase();
    if (!msg.includes('saturday')) return false;
    return true;
  });
}
checkpoints.push({ passed: callbackDetailsOk, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const weeklyPlans = JSON.parse(localStorage.getItem('weekly_plans') || '[]');
const weeklySessions = JSON.parse(localStorage.getItem('weekly_plan_sessions') || '[]');
const services = JSON.parse(localStorage.getItem('services') || '[]');

const speechService = services.find(s => s && s.code === 'speech_therapy') || null;
const otService = services.find(s => s && s.code === 'occupational_therapy') || null;
const counselingService = services.find(s => s && s.code === 'counseling') || null;

function planHasRequiredSessions(plan) {
  const sessions = weeklySessions.filter(s => s.weekly_plan_id === plan.id);
  if (!speechService || !otService || !counselingService) return false;

  const hasSpeech = sessions.some(s =>
    s.service_id === speechService.id &&
    s.day_of_week === 'tuesday' &&
    s.start_time === '16:00' &&
    s.duration_minutes === 60
  );
  const hasOt = sessions.some(s =>
    s.service_id === otService.id &&
    s.day_of_week === 'thursday' &&
    s.start_time === '17:30' &&
    s.duration_minutes === 60
  );
  const hasCounseling = sessions.some(s =>
    s.service_id === counselingService.id &&
    s.day_of_week === 'saturday' &&
    s.start_time === '11:00' &&
    s.duration_minutes === 45
  );

  return hasSpeech && hasOt && hasCounseling;
}

const planWithSessions = weeklyPlans.find(p => planHasRequiredSessions(p)) || null;

// CP1 (0.70): A weekly plan exists that includes all three specified sessions
checkpoints.push({ passed: !!planWithSessions, weight: 0.7 });

// CP2 (0.30): That plan has a non-empty custom name
let nameOk = false;
if (planWithSessions) {
  const name = String(planWithSessions.name || '').trim();
  nameOk = name.length > 0;
}
checkpoints.push({ passed: nameOk, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const pledges = JSON.parse(localStorage.getItem('donation_pledges') || '[]');
const funds = JSON.parse(localStorage.getItem('donation_funds') || '[]');

// Fund whose description indicates need-based therapy scholarships for children
const targetFund = funds.find(f => {
  if (!f) return false;
  const desc = (f.description || '').toLowerCase();
  return desc.includes('need-based scholarships') && desc.includes('therapy');
}) || null;

// CP1 (0.40): One-time $75 pledge to the correct scholarship fund
const pledgesToFund = pledges.filter(p => {
  if (!targetFund) return false;
  return p.fund_id === targetFund.id &&
    p.gift_type === 'one_time' &&
    Number(p.amount) === 75;
});
checkpoints.push({ passed: pledgesToFund.length > 0, weight: 0.4 });

// CP2 (0.30): That pledge includes an 'in_honor_of' dedication for 'The Garcia Family'
const pledgesWithDedication = pledgesToFund.filter(p => {
  if (p.dedication_type !== 'in_honor_of') return false;
  const honoree = (p.honoree_name || '').trim().toLowerCase();
  return honoree === 'the garcia family';
});
checkpoints.push({ passed: pledgesWithDedication.length > 0, weight: 0.3 });

// CP3 (0.30): Pledge has donor contact info and preferred contact method Email
let contactOk = false;
if (pledgesWithDedication.length > 0) {
  contactOk = pledgesWithDedication.some(p => {
    const hasName = !!(p.donor_name && String(p.donor_name).trim());
    const hasPhone = !!(p.donor_phone && String(p.donor_phone).trim());
    const hasEmail = !!(p.donor_email && String(p.donor_email).trim());
    const method = (p.preferred_contact_method || '').toLowerCase();
    return hasName && hasPhone && hasEmail && method === 'email';
  });
}
checkpoints.push({ passed: contactOk, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
